"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[55],{2055:(e,a,i)=>{i.d(a,{LanguageProvider:()=>r,o:()=>d});var o=i(5155),s=i(2115);let t={en:{nav:{home:"Home",about:"About Us",services:"Services",philosophy:"Philosophy",contact:"Contact"},hero:{title:"Mariner Group Home",subtitle:"Home & Community Services with dignity, care, and a name you can trust.",contactBtn:"Contact Us",callBtn:"Call Now"},about:{title:"A Home Built on Trust",description:"Mariner Group Home is more than a residence; it is a community built on dignity and trust. We provide personalized, daily support for adults with developmental disabilities in a warm, family-oriented environment where every individual is treated with the respect they deserve.",readMore:"Read More",founderQuote:"“What we give is time, patience, and a sense of belonging. That’s what real care looks like.”",founderName:"Evelyn Gonzalez, Founder"},services:{title:"What We Offer",subtitle:"Committed to Excellence in Care",personalCare:{name:"Personal Care",desc:"Personalized assistance with daily activities, ensuring comfort, cleanliness, and dignity in every interaction.",features:["Bathing & Dressing","Grooming","Oral Hygiene","Mobility Support"]},medication:{name:"Medication Management",desc:"Safe, secure, and professional administration of medications following strict health protocols.",features:["Prescription Coordination","Timely Reminders","Health Monitoring","Dosage Accuracy"]},dailyLiving:{name:"Daily Living Support",desc:"A homelike environment where every detail of daily life is managed with care and attention.",features:["Nutritious Meals","Laundry Service","Room Cleaning","Hydration Support"]},community:{name:"Community Integration",desc:"Promoting a vibrant social life through activities that connect residents with family and the local community.",features:["Social Outings","Family Visits","Recreational Events","Life Skills Training"]},disclaimer:"* All services are customized to meet the unique needs and preferences of each resident."},gallery:{title:"Our Home",subtitle:"A safe, comfortable, and dignified space designed for living.",kitchen:"Kitchen",rooms:"Private Rooms",dining:"Dining Area",patio:"Outdoor Patio"},coreValues:{title:"Core Values",dignity:{title:"Dignity & Respect",desc:"Every individual is valued and treated with the highest level of honor and regard."},personCentered:{title:"Person-Centered Care",desc:"Our support is tailored specifically to the unique needs, stories, and goals of each resident."},safety:{title:"Safety & Well-being",desc:"A secure environment provided with consistency, ensuring peace of mind for families."},independence:{title:"Independence",desc:"Empowering residents to lead autonomous lives at their own pace and comfort."},compassion:{title:"Compassion",desc:"Care that goes beyond tasks—listening, understanding, and truly being present."}},philosophy:{title:"Our Philosophy",p1:"At Mariner Group Home, we believe every person deserves to live with dignity, regardless of their abilities. We don’t start with diagnoses, we start with stories. We don’t organize routines, we build lives.",p2:"Our philosophy isn’t written in a manual — it’s a daily practice: respect, consistency, and real presence. We don’t work “for” someone. We live with them. We listen without rush and respond without scripts.",p3:"We adapt to each resident’s pace, without imposing structures foreign to their world. We want to be the right ones—the ones who show up when needed and don’t fail at the basics.",p4:"This house has no long corridors or closed doors. It has shared armchairs, simple conversations, and a cultivated calm. Our philosophy aims to do what’s right, every day."},trust:{title:"Licensed & Trusted Care",subtitle:"Your trust is our foundation. We maintain the highest standards of accountability and regulatory compliance to ensure the safety of our residents.",licensed:{title:"Fully Licensed",desc:"Operational license verified by state health and community authorities."},certified:{title:"Certified Care",desc:"Our staff holds all required certifications for adult developmental care."},compliance:{title:"Compliance First",desc:"Regularly audited to ensure 100% compliance with safety and health regulations."}},lifeAtMariner:{title:"Life at Mariner",subtitle:"Focusing on the atmosphere, the people, and the moments that make this place a true home.",sharedMoments:"Shared Moments",dailyActivities:"Daily Activities",gardening:"Gardening & Outdoors",communityBond:"Community Bond"},contact:{formTitle:"Send us a message",infoTitle:"Get in touch",infoSubtitle:"We are here to answer your questions and provide the support you need.",nameLabel:"Name",namePlaceholder:"Your name",emailLabel:"Email",emailPlaceholder:"your@email.com",messageLabel:"Message",messagePlaceholder:"How can we help?",sendBtn:"Send Message",location:"Our Location",phone:"Phone",email:"Email",successAlert:"Thank you! Your message has been successfully sent.",errorAlert:"An error occurred while sending your message. Please try again later.",viewMap:"View on Google Maps",errors:{nameReq:"Name is required",nameInvalid:"Name should only contain letters",emailReq:"Email is required",emailInvalid:"Please enter a valid email",messageReq:"Message is required",messageMax:"Max 500 characters allowed"}},footer:{companyName:"Evelyn Gonzalez Inc.",tagline:"Home & Community Services",rights:"All rights reserved."},cta:{title:"Built on Integrity",p1:"Mariner Group Home operates with full licensure from the Florida Agency for Persons with Disabilities (APD). Our team of caregivers and professionals is certified and trained to deliver compassionate, specialized support for adults with developmental disabilities.",p2:"We don’t just meet standards — we build a space where safety, dignity, and quality of life are foundational."},aboutPage:{back:"Back",heroTitle1:"About",heroTitle2:"Mariner",heroTitle3:"Group Home",heroSubtitle:"A deeper look into the decisions, values, and philosophy behind a place built not to manage people — but to truly understand them.",sectionLabel:"About the home",sectionTitle:"A different approach to care",intro1:"Mariner Group Home was not created to fill a gap in the market. It was created to question how care is usually done.",intro2:"In many places, care becomes structured to the point where it starts prioritizing efficiency over individuality. Routines are optimized, systems are refined, and slowly — almost without noticing — people are expected to fit into predefined rhythms that were never designed for them.",intro3:"This home exists as a response to that reality. Not by removing structure, but by redefining its purpose. Structure here is flexible, responsive, and built around the individual — not imposed onto them.",intro4:"What truly defines this place is not immediately visible. It is found in the pauses, in the patience of conversation, in the absence of urgency, and in the consistency of presence.",block1:"Care, in this context, is not a list of responsibilities. It is a relationship that develops over time — shaped by attention, trust, and repeated presence.",block2:"We do not approach individuals as cases to manage, but as people whose lives already carry meaning. Our role is not to define that meaning, but to support it without interference.",block3:"This is why presence matters more than perfection. Because real care is not about doing everything flawlessly — it is about showing up consistently, in ways that feel stable, respectful, and human.",dividerLabel:"Responsibility",commitmentTitle:"Commitment & Responsibility",commitment1:"Mariner Group Home operates under full licensing from the Florida Agency for Persons with Disabilities (APD). Our caregivers are trained, certified, and held to strict standards.",commitment2:"But compliance is not what defines this place. It is only the baseline. What truly matters is how those standards are lived — daily, quietly, and consistently — in every interaction.",faqTitle:"Questions you might still have",faq1Title:"How do I know this is the right place?",faq1Text:"The only real way is to understand how a place thinks. What we offer is clarity and transparency, so you can make that decision with confidence.",faq2Title:"Will my family member feel safe?",faq2Text:"Safety is built through consistency, familiarity, and respect — not just protocols.",faq3Title:"Will they be understood?",faq3Text:"Understanding takes time. That is why presence and observation are central to how we provide care.",closingQuote:"You are not just choosing a place. You are choosing who will be present in someone else's everyday life."}},es:{nav:{home:"Inicio",about:"Nosotros",services:"Servicios",philosophy:"Filosof\xeda",contact:"Contacto"},hero:{title:"Mariner Group Home",subtitle:"Servicios para el hogar y la comunidad con dignidad, cuidado y un nombre en el que puede confiar.",contactBtn:"Cont\xe1ctenos",callBtn:"Llamar Ahora"},about:{title:"Un hogar construido sobre la confianza",description:"Mariner Group Home es m\xe1s que una residencia; es una comunidad construida sobre la dignidad y la confianza. Brindamos apoyo diario y personalizado para adultos con discapacidades del desarrollo en un ambiente c\xe1lido y familiar donde cada individuo es tratado con el respeto que merece.",readMore:"Leer M\xe1s",founderQuote:"“Lo que damos es tiempo, paciencia y un sentido de pertenencia. As\xed es como se ve el verdadero cuidado.”",founderName:"Evelyn Gonzalez, Fundadora"},services:{title:"Lo que Ofrecemos",subtitle:"Comprometidos con la Excelencia en el Cuidado",personalCare:{name:"Cuidado Personal",desc:"Asistencia personalizada con las actividades diarias, asegurando comodidad, limpieza y dignidad en cada interacci\xf3n.",features:["Ba\xf1o y Vestimenta","Cuidado Personal","Higiene Bucal","Apoyo a la Movilidad"]},medication:{name:"Gesti\xf3n de Medicamentos",desc:"Administraci\xf3n segura, protegida y profesional de medicamentos siguiendo estrictos protocolos de salud.",features:["Coordinaci\xf3n de Prescripciones","Recordatorios Oportunos","Monitoreo de Salud","Precisi\xf3n en la Dosis"]},dailyLiving:{name:"Apoyo a la Vida Diaria",desc:"Un ambiente hogare\xf1o donde cada detalle de la vida diaria es gestionado con cuidado y atenci\xf3n.",features:["Comidas Nutritivas","Servicio de Lavander\xeda","Limpieza de Habitaciones","Apoyo en la Hidrataci\xf3n"]},community:{name:"Integraci\xf3n Comunitaria",desc:"Promoviendo una vida social vibrante a trav\xe9s de actividades que conectan a los residentes con sus familias y la comunidad local.",features:["Salidas Sociales","Visitas Familiares","Eventos Recreativos","Entrenamiento en Habilidades para la Vida"]},disclaimer:"* Todos los servicios se personalizan para satisfacer las necesidades y preferencias \xfanicas de cada residente."},gallery:{title:"Nuestro Hogar",subtitle:"Un espacio seguro, c\xf3modo y digno dise\xf1ado para vivir.",kitchen:"Cocina",rooms:"Habitaciones Privadas",dining:"Comedor",patio:"Patio Exterior"},coreValues:{title:"Valores Fundamentales",dignity:{title:"Dignidad y Respeto",desc:"Cada individuo es valorado y tratado con el m\xe1s alto nivel de honor y consideraci\xf3n."},personCentered:{title:"Cuidado Centrado en la Persona",desc:"Nuestro apoyo se adapta espec\xedficamente a las necesidades, historias y metas \xfanicas de cada residente."},safety:{title:"Seguridad y Bienestar",desc:"Un entorno seguro proporcionado con consistencia, garantizando tranquilidad para las familias."},independence:{title:"Independencia",desc:"Empoderar a los residentes para que lleven vidas aut\xf3nomas a su propio ritmo y comodidad."},compassion:{title:"Compasi\xf3n",desc:"Cuidado que va m\xe1s all\xe1 de las tareas: escuchar, comprender y estar verdaderamente presente."}},philosophy:{title:"Nuestra Filosof\xeda",p1:"En Mariner Group Home, creemos que cada persona merece vivir con dignidad, independientemente de sus capacidades. No empezamos con diagn\xf3sticos, empezamos con historias. No organizamos rutinas, construimos vidas.",p3:"Nos adaptamos al ritmo de cada residente, sin imponer estructuras ajenas a su mundo. Queremos ser los indicados—aquellos que aparecen cuando se necesitan y no fallan en lo b\xe1sico.",p2:"Nuestra filosof\xeda no est\xe1 escrita en un manual — es una pr\xe1ctica diaria: respeto, consistencia y presencia real. No trabajamos “para” alguien. Vivimos con ellos. Escuchamos sin prisas y respondemos sin guiones.",p4:"Esta casa no tiene pasillos largos ni puertas cerradas. Tiene sillones compartidos, conversaciones simples y una calma cultivada. Nuestra filosof\xeda busca hacer lo correcto, todos los d\xedas."},trust:{title:"Cuidado Licenciado y Confiable",subtitle:"Su confianza es nuestra base. Mantenemos los m\xe1s altos est\xe1ndares de responsabilidad y cumplimiento normativo para garantizar la seguridad de nuestros residentes.",licensed:{title:"Totalmente Licenciado",desc:"Licencia operativa verificada por las autoridades estatales de salud y comunidad."},certified:{title:"Cuidado Certificado",desc:"Nuestro personal posee todas las certificaciones requeridas para el cuidado del desarrollo de adultos."},compliance:{title:"Cumplimiento Primero",desc:"Auditado regularmente para asegurar el 100% de cumplimiento con las regulaciones de seguridad y salud."}},lifeAtMariner:{title:"La Vida en Mariner",subtitle:"Enfoc\xe1ndonos en el ambiente, las personas y los momentos que hacen de este lugar un verdadero hogar.",sharedMoments:"Momentos Compartidos",dailyActivities:"Actividades Diarias",gardening:"Jardiner\xeda y Aire Libre",communityBond:"V\xednculo Comunitario"},contact:{formTitle:"Env\xedanos un mensaje",infoTitle:"Ponte en contacto",infoSubtitle:"Estamos aqu\xed para responder tus preguntas y brindarte el apoyo que necesitas.",nameLabel:"Nombre",namePlaceholder:"Tu nombre",emailLabel:"Correo electr\xf3nico",emailPlaceholder:"tu@correo.com",messageLabel:"Mensaje",messagePlaceholder:"\xbfC\xf3mo podemos ayudarte?",sendBtn:"Enviar Mensaje",location:"Nuestra Ubicaci\xf3n",phone:"Tel\xe9fono",email:"Correo electr\xf3nico",successAlert:"\xa1Gracias! Tu mensaje ha sido enviado correctamente.",errorAlert:"Ocurri\xf3 un error al enviar tu mensaje. Por favor, int\xe9ntalo de nuevo m\xe1s tarde.",viewMap:"Ver en Google Maps",errors:{nameReq:"El nombre es obligatorio",nameInvalid:"El nombre solo debe contener letras",emailReq:"El correo es obligatorio",emailInvalid:"Ingresa un correo v\xe1lido",messageReq:"El mensaje es obligatorio",messageMax:"M\xe1ximo 500 caracteres permitidos"}},footer:{companyName:"Evelyn Gonzalez Inc.",tagline:"Servicios para el Hogar y la Comunidad",rights:"Todos los derechos reservados."},cta:{title:"Construido sobre la Integridad",p1:"Mariner Group Home opera con licencia completa de la Agencia de Florida para Personas con Discapacidades (APD). Nuestro equipo de cuidadores y profesionales est\xe1 certificado y capacitado para brindar apoyo compasivo y especializado para adultos con discapacidades del desarrollo.",p2:"No solo cumplimos con los est\xe1ndares — construimos un espacio donde la seguridad, la dignidad y la calidad de vida son fundamentales."},aboutPage:{back:"Volver",heroTitle1:"Sobre",heroTitle2:"Mariner",heroTitle3:"Group Home",heroSubtitle:"Una mirada m\xe1s profunda a las decisiones, valores y filosof\xeda detr\xe1s de un lugar construido no para gestionar personas, sino para comprenderlas verdaderamente.",sectionLabel:"Sobre el hogar",sectionTitle:"Un enfoque diferente del cuidado",intro1:"Mariner Group Home no fue creado para llenar un vac\xedo en el mercado. Fue creado para cuestionar c\xf3mo se hace habitualmente el cuidado.",intro2:"En muchos lugares, el cuidado se estructura hasta el punto en que comienza a priorizar la eficiencia sobre la individualidad. Las rutinas se optimizan, los sistemas se perfeccionan y, lentamente — casi sin darse cuenta — se espera que las personas encajen en ritmos predefinidos que nunca fueron dise\xf1ados para ellas.",intro3:"Este hogar existe como respuesta a esa realidad. No eliminando la estructura, sino redefiniendo su prop\xf3sito. La estructura aqu\xed es flexible, receptiva y construida alrededor del individuo, no impuesta sobre \xe9l.",intro4:"Lo que verdaderamente define este lugar no es visible de inmediato. Se encuentra en las pausas, en la paciencia de la conversaci\xf3n, en la ausencia de urgencia y en la consistencia de la presencia.",block1:"El cuidado, en este contexto, no es una lista de responsabilidades. Es una relaci\xf3n que se desarrolla con el tiempo, moldeada por la atenci\xf3n, la confianza y la presencia repetida.",block2:"No abordamos a las personas como casos que gestionar, sino como personas cuyas vidas ya tienen significado. Nuestro papel no es definir ese significado, sino apoyarlo sin interferencia.",block3:"Por eso la presencia importa m\xe1s que la perfecci\xf3n. Porque el cuidado real no se trata de hacer todo impecablemente, sino de estar presente de manera consistente, de formas que se sientan estables, respetuosas y humanas.",dividerLabel:"Responsabilidad",commitmentTitle:"Compromiso y Responsabilidad",commitment1:"Mariner Group Home opera bajo licencia completa de la Agencia de Florida para Personas con Discapacidades (APD). Nuestros cuidadores est\xe1n capacitados, certificados y sujetos a est\xe1ndares estrictos.",commitment2:"Pero el cumplimiento no es lo que define este lugar. Es solo la l\xednea base. Lo que realmente importa es c\xf3mo se viven esos est\xe1ndares — diaria, silenciosa y consistentemente — en cada interacci\xf3n.",faqTitle:"Preguntas que quiz\xe1s a\xfan tengas",faq1Title:"\xbfC\xf3mo s\xe9 si este es el lugar correcto?",faq1Text:"La \xfanica forma real es entender c\xf3mo piensa un lugar. Lo que ofrecemos es claridad y transparencia, para que puedas tomar esa decisi\xf3n con confianza.",faq2Title:"\xbfMi familiar se sentir\xe1 seguro?",faq2Text:"La seguridad se construye a trav\xe9s de la consistencia, la familiaridad y el respeto — no solo con protocolos.",faq3Title:"\xbfSer\xe1 comprendido/a?",faq3Text:"Comprender lleva tiempo. Por eso la presencia y la observaci\xf3n son centrales en c\xf3mo brindamos cuidado.",closingQuote:"No solo est\xe1s eligiendo un lugar. Est\xe1s eligiendo qui\xe9n estar\xe1 presente en la vida cotidiana de alguien m\xe1s."}}},n=(0,s.createContext)(void 0);function r(e){let{children:a}=e,[i,r]=(0,s.useState)("en");return(0,s.useEffect)(()=>{let e=localStorage.getItem("preferred-language");e&&("en"===e||"es"===e)&&r(e)},[]),(0,o.jsx)(n.Provider,{value:{language:i,setLanguage:e=>{r(e),localStorage.setItem("preferred-language",e)},t:e=>{let a=e.split("."),o=t[i];for(let s of a)if(!o||"object"!=typeof o||!(s in o))return console.warn("Translation key not found: ".concat(e," for language: ").concat(i)),e;else o=o[s];return"string"==typeof o||Array.isArray(o)?o:e}},children:(0,o.jsx)("div",{className:"es"===i?"lang-es":"lang-en",children:a})})}function d(){let e=(0,s.useContext)(n);if(void 0===e)throw Error("useLanguage must be used within a LanguageProvider");return e}}}]);